import{_ as a,o as t,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Legacy Quick Link Creation","description":"","frontmatter":{"title":"Legacy Quick Link Creation","slug":"legacy-link-creation"},"headers":[],"relativePath":"marketer-hub/legacy-link-creation.md","filePath":"marketer-hub/legacy-link-creation.md"}'),n={name:"marketer-hub/legacy-link-creation.md"};function r(l,e,s,p,h,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<p>Branch can be used in your social media channels, blog posts, influencer networks, etc.</p><p>You can create Short Links on the fly and add custom redirections, analytics information, and social media tags.</p><h2 id="create-a-short-link" tabindex="-1">Create a Short Link <a class="header-anchor" href="#create-a-short-link" aria-label="Permalink to &quot;Create a Short Link&quot;">​</a></h2><h3 id="options-for-creating-a-short-link" tabindex="-1">Options for creating a Short Link <a class="header-anchor" href="#options-for-creating-a-short-link" aria-label="Permalink to &quot;Options for creating a Short Link&quot;">​</a></h3><p>There are a few ways for you to create a Branch Short Link:</p><ul><li>Direct access via the <a href="https://dashboard.branch.io/quick-links/qlc/define" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Link creation via <a href="./create-quick-links.html#creating-quick-links-via-branch-web-extension-or-slack">web extension</a>.</li><li>Link creation via <a href="./branch-slack-app.html#1-add-the-branch-to-your-slack-workspace">Slack</a>.</li><li><a href="./create-quick-links.html#bulk-create-quick-links">Bulk Short Link creation</a>.</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Easily access Short Link creation by entering <a href="https://deeplink.new/" target="_blank" rel="noreferrer"><strong>deeplink.new</strong></a> in your browser.</p></div><h3 id="_1-name-your-link" tabindex="-1">1. Name your link <a class="header-anchor" href="#_1-name-your-link" aria-label="Permalink to &quot;1. Name your link&quot;">​</a></h3><p>Start by naming your link and creating an alias. Make the link title easy to remember for you and your team, as it will be displayed in the Short Links table.</p><p>If if you want to expedite your Short Link creation process, you can apply a <a href="./link-templates.html">Link Template</a> to auto-apply reusable attributes to the link. Doing so will fill in specific fields set by the selected Link Template.</p><ol><li>In the <strong>Link Title</strong> field, provide a descriptive and memorable name.</li><li>In the <strong>Link Alias</strong> field, provide an alias or link slug that ideally describes the landing page of the link.</li></ol><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>The link alias can’t be edited once the link has been created. If this field is left blank, Branch will generate a unique link hash for you.</p></div><ol start="3"><li><strong>OPTIONAL:</strong> In the <strong>Original Web URL</strong> field, provide the original link to your landing page. Doing so allows Branch to fetch and fill data for a link from a page on your website, including open graph tags and other metadata. You’ll see this metadata appear in the optional sections later in this creator. This helps reduce the number of steps for you to create a well-configured link.</li><li>Click <strong>Save &amp; Continue</strong>.</li></ol><h3 id="_2-add-analytics-tags-optional" tabindex="-1">2. Add analytics tags (optional) <a class="header-anchor" href="#_2-add-analytics-tags-optional" aria-label="Permalink to &quot;2. Add analytics tags (optional)&quot;">​</a></h3><p>Set tags on links in order to view performance on them in the Branch Dashboard.</p><p>We recommend adding analytics tags that can be used to filter and compare the performance of various links.</p><details><summary>Available tags</summary><p><strong>Feature</strong> - Feature should describe the action or product where this link is placed. In the UTM world, this is typically <code>utm_medium</code>.</p><p><strong>Channel</strong> - Channel should describe the platform or source from which you are expecting users to click this link. In the UTM world, this is typically <code>utm_source</code>.</p><p><strong>Campaign</strong> - Campaign varies from company to company, but it should describe the theme of the link. In the UTM world, this is typically <code>utm_campaign</code>.</p><p><strong>Tags</strong> - Tags are a free-form list of meaningful labels that can be used as filters in the Short Links table. Use them to keep your analytics organized.</p></details><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you are trying to add a tag from a previously created Short Link, for it to appear in the drop-down list, the previously created Short Link must be published with a click on it.</p></div><p>To add analytics tags using the drop-downs:</p><ol><li>Select pre-populated tags you&#39;ve previously used in the last 30 days, OR</li><li>Create a new tag by typing in a new tag and click <strong>Create</strong>.</li><li>Click <strong>Save &amp; Continue</strong>.</li></ol><p>.png &quot;Screen Shot 2020-07-24 at 10.20.05 AM.png&quot;)</p><h3 id="_3-add-redirects-optional" tabindex="-1">3. Add redirects (optional) <a class="header-anchor" href="#_3-add-redirects-optional" aria-label="Permalink to &quot;3. Add redirects (optional)&quot;">​</a></h3><p>Redirects tell Branch what to do if the app is not installed when the user clicks on the link. We can take the user to the app store, open a web page, or open a Deepview.</p><p>Links you create will automatically inherit redirects on iOS, Android, and Desktop per the default settings applied at your account level.</p><p>Here you have the ability to override those defaults and direct users to specific locations if the app is not installed.</p><details><summary>Available redirects</summary><p><strong>Default Redirect</strong> - Set at the account level within Link Settings. Typically set to the relevant mobile stores.</p><p><strong>Web URL</strong> - Send users to a specific web page if they don’t have to the app to avoid any unexpected flow to the app store.</p><p><strong>Deepview</strong> - Send users to a specific Deepview you may have created within the Branch dashboard. Copy the key and paste it into the text box. This is useful if you want to present the user with a preview of the content before taking them directly to the app store, but should not be set for the Desktop option.</p></details><p>To override your default redirects:</p><ol><li>Using the drop-downs for the respective platforms, select the location you want users redirected to.</li><li>Click <strong>Save &amp; Continue</strong>.</li></ol><p>.png &quot;Screen Shot 2020-07-24 at 10.41.01 AM.png&quot;)</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Use the <strong>Web-Only Link</strong> option if you are choosing a page that should always be opened in the browser. Examples include T&amp;C pages and policy pages. We recommend keeping this unchecked if you have an in-app deep link.</p><p>This option always force opens the web browser on iOS. However, on Android, it still opens the app if Android App Links are enabled for your domain. This means, web-only links will always open the app on Android.</p></div><h3 id="_4-add-link-data-optional" tabindex="-1">4. Add link data (optional) <a class="header-anchor" href="#_4-add-link-data-optional" aria-label="Permalink to &quot;4. Add link data (optional)&quot;">​</a></h3><p>Add the data that you want to be passed to your app via this link. This data is also used to configure link functions like routing, attribution windows, etc. All keys and values are case-sensitive.</p><p>Keys are passed as identifiers in Link Data. Think of key as the &quot;Name&quot; identifier of a person named John. In &quot;Name: John&quot;, &quot;Name&quot; is the key.</p><p>Values are the information corresponding to keys. Think of value as the &quot;John&quot; value of a person named John. In &quot;Name: John&quot;, &quot;John&quot; is the value.</p><p>To add link data:</p><ol><li>Click the <strong>Add Key/Value Pair</strong> button.</li><li>Using the <strong>Key</strong> drop-down menu, select the key for which you want to pass a value.</li><li>Using the <strong>Value</strong> drop-down menu, select the value for the key you selected.</li><li>Click <strong>Save &amp; Continue</strong>.</li></ol><p>.png &quot;Screen Shot 2020-08-04 at 8.29.20 AM.png&quot;)</p><h3 id="_5-add-social-media-tags-optional" tabindex="-1">5. Add social media tags (optional) <a class="header-anchor" href="#_5-add-social-media-tags-optional" aria-label="Permalink to &quot;5. Add social media tags (optional)&quot;">​</a></h3><p>When a link is shared on social media platforms, it generally shows a preview of title, description, and image. Note that your image may be cropped and aligned differently depending on the social platform.</p><p>To add social media tags provide the following information:</p><ol><li><p><strong>Title</strong></p></li><li><p><strong>Description</strong></p></li><li><p><strong>Image URL</strong></p><ol><li>This will be automatically populated from OG Tags included on the redirection URL.</li><li>To upload a different image, click the <strong>Upload Image</strong> tab and select the appropriate file.</li></ol></li><li><p>Click <strong>Save Link</strong>.</p></li></ol><p>.png &quot;Screen Shot 2020-08-04 at 8.41.27 AM.png&quot;)</p><h3 id="_6-validate-and-share" tabindex="-1">6. Validate and share <a class="header-anchor" href="#_6-validate-and-share" aria-label="Permalink to &quot;6. Validate and share&quot;">​</a></h3><ol><li><p>In the <strong>Validation</strong> section, address any errors if they exist.</p></li><li><p>In the <strong>Preview</strong> section you can:</p><ol><li>Copy the link.</li><li>Download the link embedded in a QR code (available in a JPEG or SVG file).</li><li>Text the link to any number you provide.</li></ol></li><li><p>Click <strong>Close</strong>.</p></li></ol><p>.png &quot;Screen Shot 2020-08-04 at 8.53.57 AM.png&quot;)</p><h2 id="create-short-links-via-branch-web-extension-or-slack" tabindex="-1">Create Short Links via Branch web extension or Slack <a class="header-anchor" href="#create-short-links-via-branch-web-extension-or-slack" aria-label="Permalink to &quot;Create Short Links via Branch web extension or Slack&quot;">​</a></h2><h4 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h4><p>Using Branch&#39;s web extension for Short Link creation enables you to quickly create links for any of your social marketing purposes without having to log into your Branch Dashboard. These links can be used in your social media channels, blog posts, influencer networks, etc. <strong>They cannot, however, be used to create links for Ads, Email, or Journeys</strong>.</p><h4 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h4><ul><li><p>Download the Extension:</p><ul><li><a href="https://chrome.google.com/webstore/detail/branch-link-creator/pekdpppibljpmpbcjelehhnldnfbglgf?hl=en-US" target="_blank" rel="noreferrer">Chrome</a></li></ul></li><li><p>Download the <a href="https://api2.branch.io/v1/slack-app/install" target="_blank" rel="noreferrer">Branch Slack App</a></p></li><li><p>Creating links via the Branch Link Creator web extension requires you have deep link data hosted in your website source code. Read our article on <a href="./creating-a-deep-link.html">Deep Links</a>.</p></li></ul><h4 id="_1-one-time-setup-provide-your-branch-key" tabindex="-1">1. One-time setup: provide your Branch Key <a class="header-anchor" href="#_1-one-time-setup-provide-your-branch-key" aria-label="Permalink to &quot;1. One-time setup: provide your Branch Key&quot;">​</a></h4><p>Before you can create a link, you must authenticate by providing your Branch Key.</p><ol><li>In the <strong>Add Branch Key</strong> modal, input your <strong>Branch Key</strong>. Learn how to find your Branch key <a href="./create-quick-links.html">here</a>.</li><li>Click Save Key.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you need to change your Branch Key, click on the extension, and click <strong>Change Key</strong>.</p></div><h4 id="_2-define-your-link" tabindex="-1">2. Define your link <a class="header-anchor" href="#_2-define-your-link" aria-label="Permalink to &quot;2. Define your link&quot;">​</a></h4><p>You can define your link with the following:</p><ol><li><p>Branch automatically retrieves and applies the metadata hosted in your website code to your Short Link. The following metadata is defined and/or can be edited.</p><ol><li><p><strong>General</strong></p><ol><li>Link Name</li><li>Link Alias</li></ol></li><li><p><strong>Analytics Tags</strong></p><ol><li>Channel</li><li>Campaign</li><li>Feature</li></ol></li></ol></li><li><p><strong>Web-only Link</strong> - If you have a page that should be opened in the browser, use this option. Some examples are T&amp;C pages, Policy pages, etc. We recommend if you have a deep link in-app, keep it unchecked.</p></li><li><p><strong>If App Not Installed</strong> - Always redirect to mobile web.</p></li><li><p>Click <strong>Create Link</strong>.</p></li></ol><h4 id="_3-download-share-copy-link" tabindex="-1">3. Download / share / copy link <a class="header-anchor" href="#_3-download-share-copy-link" aria-label="Permalink to &quot;3. Download / share / copy link&quot;">​</a></h4><p>Once created, you have several options to disseminate your link:</p><ul><li>Copy</li><li>[Web Extension Only] Generate QR code (available as JPEG and SVG)</li></ul><h2 id="bulk-create-short-links" tabindex="-1">Bulk create Short Links <a class="header-anchor" href="#bulk-create-short-links" aria-label="Permalink to &quot;Bulk create Short Links&quot;">​</a></h2><p>To create Short Links in bulk:</p><ol><li><p>Navigate to the <a href="https://branch.dashboard.branch.io/quick-links/manager" target="_blank" rel="noreferrer"><strong>Manager tab</strong></a> in LinkHub in the Branch Dashboard.</p></li><li><p>Click the <strong>Create Bulk Links</strong> button.</p></li><li><p>Add the following for each Short Link:</p><ol><li>campaign</li><li>channel</li><li>feature</li><li>stage</li><li>tags</li><li>alias</li><li>data</li><li>$marketing_title</li><li>$og_description</li><li>$fallback_url</li><li>$desktop_url</li></ol></li><li><p>Click <strong>Create Links</strong>.</p></li></ol><h2 id="more-short-link-view-options" tabindex="-1">More Short Link view options <a class="header-anchor" href="#more-short-link-view-options" aria-label="Permalink to &quot;More Short Link view options&quot;">​</a></h2><p>The <a href="https://branch.dashboard.branch.io/quick-links/manager?v=latest" target="_blank" rel="noreferrer">Short Links page</a> in the Branch Dashboard has a limit of 1,000 and only shows those Short Links created in the last 6 months. However, there are a few ways to view the data associated with these links.</p><p><strong>Option 1</strong>: Append query parameters to the Branch Link</p><ul><li>To view the link data of any Branch link, you can simply append <code>?debug=true</code> to it for the link data.</li><li>To view the click/install/opens stats, you can append <code>?stats=true</code>.</li><li>To edit Short Links or download an associated QR code, you can simply append <code>?edit=true</code>.</li></ul><p>Examples:<br><a href="https://example.app.link/ashfiashf?debug=true" target="_blank" rel="noreferrer">https://example.app.link/ashfiashf?debug=true</a></p><p><a href="https://example.app.link/jasofjaosg?stats=true" target="_blank" rel="noreferrer">https://example.app.link/jasofjaosg?stats=true</a></p><p><a href="https://example.app.link/ashfiashf?edit=true" target="_blank" rel="noreferrer">https://example.app.link/ashfiashf?edit=true</a></p><p><strong>Option 2</strong>: HTTP API</p><p>Use our <code>v1/url/ endpoint</code> in our HTTP API to view any of the deep link data associated with any Branch link. The CURL request could be of the form: <code>curl -XGET &#39;https://api.branch.io/v1/url?url=https://example.app.link/ashfiashf&amp;branch_key=key_live_mUasfsafas1pgdS9FWoB4xceexFdxiF13</code></p>',72)])])}const k=a(n,[["render",r]]);export{u as __pageData,k as default};
